text:
&:active,
  &.active,
  .open > .dropdown-toggle& {
    color: @color;
    background-color: darken(@background, 10%);
    border-color: darken(@border, 12%);

    &:hover,
    &:focus,
    &.focus {
      color: @color;
      background-color: darken(@background, 17%);
      border-color: darken(@border, 25%);
    }
  }

&-mouse {
  width: 28px;
  height: 42px;
  border-radius: 14px;
  border: 2px solid @text-color-light;
  margin: auto;
  & .mouse-bar {
    width: 4px;
    height: 12px;
    border-radius: 2px;
    background: @text-color-light;
    margin: 5px auto auto;
  }
}

&-inline {
  .@{menuPrefixCls}-submenu-arrow {
    transform: rotate(90deg);
    transition: transform 0.3s;
  }
  & .@{menuPrefixCls}-submenu-open > .@{menuPrefixCls}-submenu-title {
    .@{menuPrefixCls}-submenu-arrow {
      transform: rotate(-90deg);
    }
  }
}

& > .panel-heading {
  color: @heading-text-color;
  background-color: @heading-bg-color;
  border-color: @heading-border;

  + .panel-collapse > .panel-body {
    border-top-color: @border;
  }
  .badge {
    color: @heading-bg-color;
    background-color: @heading-text-color;
  }
}

> .user-body {
  padding: 15px;
  border-bottom: 1px solid #f4f4f4;
  border-top: 1px solid #dddddd;
  .clearfix();
  a {
    color: #444 !important;
    @media (max-width: @screen-sm-max) {
      background: #fff !important;
      color: #444 !important;
    }
  }
}

@media (max-width: @screen-header-collapse) {
  .main-header {
    position: relative;
    .logo,
    .navbar {
      width: 100%;
      float: none;
    }
    .navbar {
      margin: 0;
    }
    .navbar-custom-menu {
      float: right;
    }
  }
}

&-item-active,
  &-submenu-active > &-submenu-title {
    background-color: #eaf8fe;
  }

  &-item-selected {
    background-color: #eaf8fe;
    // fix chrome render bug
    transform: translateZ(0);
  }

  &-submenu-selected {
    background-color: #eaf8fe;
  }

body div.ui-datalist {
    div.ui-datalist-content {
        text-align: left;

        li.ui-datalist-item a {
            color:@light-blue;
        }
    }
    &.no-border div.ui-datalist-content {
        border: none;
    }

    ul.ui-datalist-data {
        padding-left: 30px;
    }
}

li.dropdown {

    &.open {
        width: 100%;
    }
    a.dropdown-toggle {
        background-color:transparent!important;
    }

    ul.dropdown-menu {
        position: relative;
        background-color:#fff!important;
        width: 100%;
    }
}

ul.nav.navbar-nav ul.dropdown-menu li.active a {
  border-left-color: @color;
  @media (max-width: @screen-sm) {
    border-left: none;
    font-weight: bolder;
    color: #fff;
    background: @color;
    &:hover {
      background-color: darken(@color, 5%);
    }
  }
}

@media (max-width: @screen-xm) {
    body div.ui-sidebar {
        &.ui-sidebar-bottom {
            .transform(translateY(150%));
            &.ui-sidebar-active {
                .transform(translateY(0));
            }
        }
    }
    .ui-sidebar-mask {
        z-index: @sidebar-mask-zindex!important;
    }
}

&.ui-inputswitch-checked {

  background-color: lighten(@light-blue, 10%);
  border-color: darken(lighten(@light-blue, 10%), 5%);

  .ui-inputswitch-handle {
    .btn-interactions(@light-blue);
    background-color: @light-blue;
    border-color: darken(@light-blue, 5%);
    color: #fff;

    &.ui-state-focus {
      .input-shadow;
    }
  }
}

@media screen and (max-width: 600px) {
    .grouping{
        width: 100%;
        max-width: 700px;
        padding: 50px 15px;
        font-size: 1rem;
        p {
            font-size: 1.50rem;
        }
        a {
            padding: 15px;
        }
    }
}

&.box-solid {
    .ui-picklist-caption, .ui-orderlist-caption {
        background-color: @color;
        border-color: @color;
        color: @text-color
    }

    .ui-picklist-buttons-cell, .ui-orderlist-controls {
        button {
            background-color: @color;
            .btn-interactions(@color);
        }
    }

}

&.fc-button-active, &.fc-button-primary.fc-button-active {
    color: #fff;
    border: 1px solid #ddd;
    background: @light-blue;

    &:not(:disabled) {
        .btn-interactions(@light-blue);
    }

    &:hover, &:focus, &:active {
        color: #fff;
    }
}

li {
    &.ui-selectlistbox-item, &.ui-multiselectlistbox-item {
        position: relative;
        overflow: hidden;
        padding: 3px 6px;

        &.ui-state-highlight {
            border-radius: @default-border-radius;
        }
    }
    &.ui-listbox-outline {
        outline:none;
    }
}

&:before {
    font-family: 'Glyphicons Halflings';
    color: @admin-text-color;
    position: relative;
    font-size: @spinner-icon-size;
    top: -3px;
    left: 2px;
    font-weight: bold;
    overflow: hidden;
    content: "\e260" !important;
    @media (max-width: @screen-sm) {
        font-size: @spinner-icon-size + 1;
    }
}

&:before {
    font-family: 'Glyphicons Halflings';
    color: @admin-text-color;
    position: relative;
    font-size: @spinner-icon-size;
    top: -6px;
    left: 2px;
    font-weight: bold;
    overflow: hidden;
    content: "\e259" !important;
    @media (max-width: @screen-sm) {
        font-size: @spinner-icon-size + 1;
    }
}

&:before {
    font-family: 'Glyphicons Halflings';
    color: @admin-text-color;
    position: relative;
    margin: 0 7px;
    top: -5px;
    font-size: @glyphicon-icon-size + 1;
    overflow: hidden;
    content: "\e259" !important;
    @media (min-width: (@screen-md + 1)) {
        font-weight: bold;
    }
}

span.ui-icon-arrowthick-1-w {
  background-image: none !important;
  display: inline !important;
  text-indent: 0;
  &:before {
    font-family: FontAwesome;
    color: #fff;
    position: relative;
    font-size: @font-awesome-icon-size;
    top: -3px;
    overflow: hidden;
    content: "\f112" !important;
  }

}

span.ui-icon-arrowthick-1-e {
  background-image: none !important;
  display: inline !important;
  text-indent: 0;
  &:before {
    font-family: FontAwesome;
    color: #fff;
    position: relative;
    font-size: @font-awesome-icon-size;
    top: -3px;
    overflow: hidden;
    content: "\f064" !important;
  }
}

> a {
  background: darken(@sidebar-light-bg, 5%);
  color: @sidebar-light-color;
  // Hover and active states
  &,
  &:hover,
  &:focus {
    border-left-color: @gray-lte;
    border-bottom-color: @gray-lte;
  }
  &:hover,
  &:focus,
  &:active {
    background: darken(@sidebar-light-bg, 3%);
  }
}

> .dropdown-menu > li .menu {
  // Links inside the menu
  > li > a {
    color: #444444;
    overflow: hidden;
    text-overflow: ellipsis;
    padding: 10px;
    // Icons inside the menu
    > .glyphicon,
    > .fa,
    > .ion {
      width: 20px;
    }
  }

}

@media (max-width: @screen-sm-max) {
  .navbar-custom-menu > .navbar-nav {
    float: right;
    > li {
      position: static;
      > .dropdown-menu {
        position: absolute;
        right: 5%;
        left: auto;
        border: 1px solid #ddd;
        background: #fff;
      }
    }
  }
}

a.ui-state-highlight, span.ui-state-highlight {
    text-shadow: none;
    color: #222;
    transform: scale(0.9);
    border-radius: 50%;
    background: #fff;
    border: 1px solid @light-blue;
    &.ui-state-active {
        color: @calendar-selected-color;
        background: @light-blue;
    }
}

