@media (max-width: @screen-sm) {
    .ui-fileupload {
        span.ui-icon-plusthick, button.ui-fileupload-upload span.ui-icon-arrowreturnthick-1-n, button.ui-fileupload-cancel span.ui-icon-cancel {
            &:before {
                top: 0 !important;
                margin-left: -2px !important;
            }
        }
    }
}

&.ui-state-disabled {
    &:hover, &.ui-state-hover {
        background-color: darken(@btn-background-color, 0%);
    }
    &:focus, &.ui-state-focus {
        background-color: darken(@btn-background-color, 0%);
    }
    &:active, &.ui-state-focus {
        background-color: darken(@btn-background-color, 0%);
    }
}

&.ui-state-disabled {
    &:hover, &.ui-state-hover {
        background-color: darken(@bg-color, 0%) !important;
    }
    &:focus, &.ui-state-focus {
        background-color: darken(@bg-color, 0%) !important;
    }
    &:active, &.ui-state-active {
        background-color: darken(@bg-color, 0%) !important;
    }
