@-moz-document url-prefix() {
    div.ui-picklist-buttons-cell button {
        > span:before {
            bottom: 15px;
        }

        &.ui-picklist-button-move-bottom, &.ui-picklist-button-move-down {
            > span:before {
                bottom: 16px;
            }
        }

    }

}

@-moz-document url-prefix() {
    button.ui-autocomplete-dropdown  span.ui-icon.ui-icon-triangle-1-s:before {
        top: -19px!important;
        left: 2px;
    }

    .ui-material button.ui-autocomplete-dropdown  span.ui-icon-triangle-1-s:before {
        top: -8px!important;
    }
}

@supports (font: -moz-document) {
    button.ui-autocomplete-dropdown  span.ui-icon-triangle-1-s:before {
        top: -16px!important;
        left: 2px;
    }
    .ui-material button.ui-autocomplete-dropdown  span.ui-icon-triangle-1-s:before {
        top: -8px!important;
    }
}
